function isVowel(c) {
  return ['a', 'e', 'i', 'o', 'u'].includes(c);
}

function countVowelStrings(words, left, right) {
  let count = 0;
  for (let i = left; i <= right; i++) {
    if (isVowel(words[i][0]) && isVowel(words[i][words[i].length - 1])) {
      count++;
    }
  }
  return count;
}
```

